+            for (; i < a.length; i++) {
+                Assert.assertTrue(Float16.compare(shortBitsToFloat16(r[i]), shortBitsToFloat16(mathf.apply(a[i]))) == 0 ||
+                                    isWithin1Ulp(r[i], strictmathf.apply(a[i])));
