+            withToString("Float16[-i * 5]", (int s) -> {
+                return fill(s * BUFFER_REPS,
+                            i -> genValue(-i * 5));
+            }),
+            withToString("Float16[i * 5]", (int s) -> {
+                return fill(s * BUFFER_REPS,
+                            i -> genValue(i * 5));
+            }),
+            withToString("Float16[i + 1]", (int s) -> {
+                return fill(s * BUFFER_REPS,
+                            i -> (((short)(i + 1) == 0) ? genValue(1) : genValue(i + 1)));
+            })
+    );
